-- Relay seed — generated from data.js. Run after 01_schema.sql + 02_rls.sql.
-- Order respects FKs (employees + weekly_summaries first).
set session_replication_role = replica; -- defer FK checks during load

on conflict (id) do update set email = excluded.email, name = excluded.name, initials = excluded.initials, manager_id = excluded.manager_id, dept = excluded.dept, sub = excluded.sub, role_level = excluded.role_level, title = excluded.title, is_cross_dept = excluded.is_cross_dept, data = excluded.data;

on conflict (id) do update set data = excluded.data;

on conflict (id) do update set bd_id = excluded.bd_id, product_id = excluded.product_id, data = excluded.data;

on conflict (id) do update set data = excluded.data;

on conflict (id) do update set dept = excluded.dept, owner_id = excluded.owner_id, data = excluded.data;

on conflict (id) do update set dept = excluded.dept, status = excluded.status, data = excluded.data;

on conflict (id) do update set author_id = excluded.author_id, dept = excluded.dept, sub = excluded.sub, report_date = excluded.report_date, data = excluded.data;

on conflict (id) do update set owner_id = excluded.owner_id, dept = excluded.dept, work_date = excluded.work_date, data = excluded.data;

on conflict (id) do update set owner_id = excluded.owner_id, dept = excluded.dept, status = excluded.status, data = excluded.data;

on conflict (id) do update set dept = excluded.dept, state = excluded.state, data = excluded.data;

on conflict (id) do update set weekly_id = excluded.weekly_id, author_id = excluded.author_id, data = excluded.data;

on conflict (id) do update set dept = excluded.dept, data = excluded.data;

on conflict (id) do update set agent = excluded.agent, user_id = excluded.user_id, human_action = excluded.human_action, data = excluded.data;

on conflict (id) do update set agent = excluded.agent, data = excluded.data;

on conflict (id) do update set agent = excluded.agent, data = excluded.data;

on conflict (id) do update set owner_id = excluded.owner_id, data = excluded.data;

on conflict (id) do update set data = excluded.data;

on conflict (id) do update set data = excluded.data;

on conflict (id) do update set data = excluded.data;

on conflict (id) do update set agent = excluded.agent, data = excluded.data;

on conflict (id) do update set data = excluded.data;


set session_replication_role = origin;
