insert into guideline_proposals (id, agent, data) values
  ('gp-1', 'Rollup', $relay${"id":"gp-1","agent":"Rollup","proposedBy":"Curator","ts":"2026-05-25 06:10 IST","title":"Always pair each Risk with an explicit Ask","rationale":"In the last 7 days, L2/L3 edits added an \"Ask\" to 6 of 8 risk items they reviewed. The pattern is consistent across departments.","currentRule":"Weekly Risks section: state the risk, owner, and ETA.","proposedRule":"Weekly Risks section: state the risk, owner, ETA, **and a specific Ask (resource, decision, or escalation)**.","evidence":["eng-2","eng-3","eng-5"],"state":"pending"}$relay$::jsonb),
  ('gp-2', 'Dispatcher', $relay${"id":"gp-2","agent":"Dispatcher","proposedBy":"Curator","ts":"2026-05-25 06:10 IST","title":"Owner inference must follow manager_id, not domain match","rationale":"Dispatcher matched \"Backend reporting gap\" to Vijay (Central Ops) based on keyword similarity, but the org tree puts Backend under Pavan Teja. Three similar errors this week.","currentRule":"Match action items to people via name → role → domain keywords.","proposedRule":"Match action items to people via **explicit name first, then employee.manager_id of the mentioned sub-team, then domain keywords as fallback only**.","evidence":["eng-3"],"state":"pending"}$relay$::jsonb),
  ('gp-3', 'Rollup', $relay${"id":"gp-3","agent":"Rollup","proposedBy":"Curator","ts":"2026-05-25 06:10 IST","title":"Highlights must credit the driver","rationale":"L2 edits consistently add attribution to highlight items. Pattern detected in 4 of 5 recent Highlights edits.","currentRule":"Highlights: 1–2 sentences, factual.","proposedRule":"Highlights: 1–2 sentences, factual, **and credit the person or sub-team driving the result when known**.","evidence":["eng-9"],"state":"pending"}$relay$::jsonb),
  ('gp-4', 'Sentry', $relay${"id":"gp-4","agent":"Sentry","proposedBy":"Curator","ts":"2026-05-24 06:10 IST","title":"KPI red > 1 week auto-escalates to P1","rationale":"Sentry suggested P2 for the NAT-throttle task; Pavan G overrode to P1 with the rule \"any KPI red > 1w gets P1\". Same override pattern seen twice in May.","currentRule":"Suggested-task priority = severity × reach.","proposedRule":"Suggested-task priority = severity × reach, **with a floor of P1 if the linked KPI has been red for > 7 days**.","evidence":["eng-10"],"state":"approved","decidedBy":"NW0005116","decidedAt":"2026-05-24 14:22 IST"}$relay$::jsonb),
  ('gp-5', 'Rollup', $relay${"id":"gp-5","agent":"Rollup","proposedBy":"Curator","ts":"2026-05-22 06:10 IST","title":"Skip draft generation if input set is incomplete","rationale":"Rejected drafts for missing-input weeks waste tokens and trigger false-confidence flags. Pavan G rejected w-dsalgo-21 explicitly for this reason.","currentRule":"Generate weekly draft every Monday 06:00 regardless of input completeness.","proposedRule":"Generate weekly draft when **≥ 80% of expected daily reports are present**; else queue with note.","evidence":["eng-6"],"state":"pending"}$relay$::jsonb)
